#include <stdio.h>
#include <stdlib.h>

int cmp_desc(const void *a, const void *b) {
    return *(int *)b - *(int *)a; // descending
}
int cmp_asc(const void *a, const void *b) {
    return *(int *)a - *(int *)b; // ascending
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *C = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &C[i]);
        // collect odd (0‑blocks) and even (1‑blocks) separately
        int oddCnt = (N + 1) / 2;
        int evenCnt = N / 2;
        int *odd = (int*)malloc(oddCnt * sizeof(int));
        int *even = (int*)malloc(evenCnt * sizeof(int));
        int oi = 0, ei = 0;
        for (int i = 0; i < N; ++i) {
            if ((i & 1) == 0) odd[oi++] = C[i]; // 0‑block
            else even[ei++] = C[i]; // 1‑block
        }
        qsort(odd, oddCnt, sizeof(int), cmp_desc);
        qsort(even, evenCnt, sizeof(int), cmp_asc);
        // rebuild optimal array
        oi = ei = 0;
        long long ans = 0;
        long long zeroCnt = 0;
        for (int i = 0; i < N; ++i) {
            if ((i & 1) == 0) {
                C[i] = odd[oi++];
                zeroCnt += C[i];
            } else {
                C[i] = even[ei++];
                ans += zeroCnt * (long long)C[i];
            }
        }
        // output
        for (int i = 0; i < N; ++i) {
            if (i) printf(" ");
            printf("%d", C[i]);
        }
        printf("\n%lld\n", ans);
        free(C); free(odd); free(even);
    }
    return 0;
}

