import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long[] C = new long[N];
            for (int i = 0; i < N; i++) C[i] = fs.nextLong();
            List<Long> odd = new ArrayList<>(); // 0‑blocks
            List<Long> even = new ArrayList<>(); // 1‑blocks
            for (int i = 0; i < N; i++) {
                if ((i & 1) == 0) odd.add(C[i]); else even.add(C[i]);
            }
            odd.sort(Collections.reverseOrder()); // descending
            Collections.sort(even); // ascending
            long zeroCnt = 0, ans = 0;
            int oi = 0, ei = 0;
            for (int i = 0; i < N; i++) {
                if ((i & 1) == 0) {
                    C[i] = odd.get(oi++);
                    zeroCnt += C[i];
                } else {
                    C[i] = even.get(ei++);
                    ans += zeroCnt * C[i];
                }
            }
            for (int i = 0; i < N; i++) {
                if (i > 0) out.append(' ');
                out.append(C[i]);
            }
            out.append('\n').append(ans).append('\n');
        }
        System.out.print(out.toString());
    }

    // Fast scanner for competitive programming
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { return Long.parseLong(next()); }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            if (c == -1) return "";
            do { sb.append((char) c); } while ((c = readByte()) != -1 && c > ' ');
            return sb.toString();
        }
    }
}

